SELECT COUNT(*) AS total_io_units
FROM io_units
WHERE status = 'Active';

SELECT status, COUNT(*) AS unit_count
FROM io_units
GROUP BY status;

SELECT signal_name, description
FROM io_signals
WHERE INSTR(description, 'temperature') > 0;

SELECT log_message
FROM io_unit_logs
WHERE io_unit_id = 0;

SELECT COUNT(*) 
FROM io_unit_logs 
WHERE log_type = 'Info';
